100	static int get_input_data(EEPTPU_SA* eepsa, unsigned char* addr_img, int img_w, int img_h, unsigned char* inbuf, int* inlen)
101	{
102		int net_in_c = eepsa->addr_in.shape[1];
103		int net_in_h = eepsa->addr_in.shape[2];
104		int net_in_w = eepsa->addr_in.shape[3];
105		int net_in_exp = eepsa->addr_in.exp;
106		float* mean = eepsa->mean.data();
107		float* norm = eepsa->norm.data();
108	
109		// get input image
110		// store camera image data, format is bgrbgrbgr.... or rgbrgbrgbrgb....
111		unsigned char* inputbuf = addr_img;
112		// resize image.
113		unsigned char* inbuf_resized = (unsigned char*)0x39000000; //(unsigned char*)malloc(net_in_w*net_in_h*net_in_c);
114		if (inbuf_resized == NULL) return eeperr_Malloc;
115		if (net_in_c == 3)
116		{
117			resize_bilinear_c3(inputbuf, img_w, img_h, inbuf_resized, net_in_w, net_in_h);
118		}
119		else if (net_in_c == 1)
120		{
121			resize_bilinear_c1(inputbuf, img_w, img_h, inbuf_resized, net_in_w, net_in_h);
122		}
123	
124		// set to hw format
125		// inputbuf:  hwc
126		*inlen = net_in_w*net_in_h*32;
127		memset(inbuf, 0, *inlen);
128		unsigned char *pdst = inbuf;
129		unsigned char *psrc = inbuf_resized;
130		int mul_val = pow(2, net_in_exp);
131		if (net_in_c == 3)
132		{
133			vector<float> mul2;
134			for (int k = 0; k < net_in_c; k++) mul2.push_back(norm[k]*mul_val);
135			for (int hw = 0; hw < net_in_w*net_in_h; hw++)
136			{
137				short us;
138	
139	        #if 0 // src data is bgrbgrbgr....; dst use bgr
140				us = round( ((float)*psrc - mean[0]) * mul2[0]);
141				psrc++;
142				*pdst++ = us & 0xff;
143				*pdst++ = (us >> 8) & 0xff;
144	
145				us = round( ((float)*psrc - mean[1]) * mul2[1]);
146				psrc++;
147				*pdst++ = us & 0xff;
148				*pdst++ = (us >> 8) & 0xff;
149	
150				us = round( ((float)*psrc - mean[2]) * mul2[2]);
151				psrc++;
152				*pdst++ = us & 0xff;
153				*pdst++ = (us >> 8) & 0xff;
154				pdst += 26;
155	        #else  // src data is rgbrgbrgb....; dst use bgr
156				us = round( ((float)*psrc++ - mean[0]) * mul2[0]);
157				pdst[4] = us & 0xff;
158				pdst[5] = (us >> 8) & 0xff;
159	
160				us = round( ((float)*psrc++ - mean[1]) * mul2[1]);
161				pdst[2] = us & 0xff;
162				pdst[3] = (us >> 8) & 0xff;
163	
164				us = round( ((float)*psrc++ - mean[2]) * mul2[2]);
165				pdst[0] = us & 0xff;
166				pdst[1] = (us >> 8) & 0xff;
167				pdst += 32;
168	        #endif
169			}
170			mul2.clear();
171		}
172		else if (net_in_c == 1)
173		{
174			float mul2 = norm[0] * mul_val;
175			for (int hw = 0; hw < net_in_w*net_in_h; hw++)
176			{
177				// gray
178				unsigned short us;
179				us = round( ((float)*psrc++ - mean[0]) * mul2);
180				*pdst++ = us & 0xff;
181				*pdst++ = (us >> 8) & 0xff;
182	
183				pdst += 30;
184			}
185		}
186		// free(inbuf_resized);
187		return 0;
188	}
