601					    XTime_GetTime(&tBegin);
602					    ret = yolo3_detection_output_forward(outputs, top_blobs);
603					    XTime_GetTime(&tEnd);
604					    tused_det_out = ((tEnd-tBegin)*1000000)/(COUNTS_PER_SECOND);
