650	
651					        int label = values[0];
652					        float prob = values[1];
653					        float scale_x = values[2];
654					        float scale_y = values[3];
655					        float scale_w = values[4];
656					        float scale_h = values[5];
657	
658					        if(scale_x < 0) scale_x = 0;
659					        if(scale_y < 0) scale_y = 0;
660					        if(scale_w < 0) scale_w = 0;
